'use server'

import { resend } from '@/utils/api/resend'
import WeeklySummaryEmail from '@/emails/WeeklySummary'
import { createClient } from '@/utils/supabase/server'

export async function sendWeeklyReport(emailTo?: string) {
    try {
        const supabase = await createClient()
        const { data: { user } } = await supabase.auth.getUser()

        // If no specifically provided email, try to use user's email
        const targetEmail = emailTo || user?.email

        if (!targetEmail || !user) {
            return { success: false, error: 'No authenticated user or email address found.' }
        }

        // Fetch Real Weekly Stats
        const today = new Date()
        const startDate = new Date(today)
        startDate.setDate(today.getDate() - 7) // Last 7 days

        // 1. Get Weekly Entries
        const { data: weeklyEntries } = await supabase
            .from('daily_entries')
            .select(`
                id,
                date,
                platform_earnings ( amount, tips, miles, hours ),
                expenses ( amount, category )
            `)
            .eq('user_id', user.id)
            .gte('date', startDate.toISOString().split('T')[0])
            .lte('date', today.toISOString().split('T')[0])

        // 2. Fetch Profile/Vehicle for Calculations
        const { data: profile } = await supabase.from('profiles').select('state_code').eq('id', user.id).single()
        const { data: vehicle } = await supabase.from('vehicles').select('mpg').eq('user_id', user.id).eq('is_primary', true).single()

        const stateCode = profile?.state_code || 'DEFAULT'
        const mpg = vehicle?.mpg || 25

        // 3. Dynamically fetch gas price (reuse logic if possible, or just fetch)
        // For server action speed, we might want to skip external API if not cached, but let's try to be accurate
        // We'll import the cached getter
        const { getGasPrice } = await import('@/utils/api/external')
        const currentGasPrice = await getGasPrice(stateCode)
        const { calculateFinancials } = await import('@/utils/calculations')

        let totalGross = 0
        let totalExpenses = 0 // Explicit expenses
        let totalMiles = 0

        if (weeklyEntries) {
            weeklyEntries.forEach(entry => {
                entry.platform_earnings.forEach((p: any) => {
                    totalGross += (p.amount || 0) + (p.tips || 0)
                    totalMiles += (p.miles || 0)
                })
                entry.expenses.forEach((e: any) => {
                    totalExpenses += (e.amount || 0)
                })
            })
        }

        // Calculate Financials (Net Profit including Fuel & Wear)
        const financials = calculateFinancials({
            grossEarnings: totalGross,
            expenses: totalExpenses,
            miles: totalMiles,
            stateCode,
            mpg,
            gasPrice: currentGasPrice
        })

        const realStats = {
            gross: totalGross,
            expenses: totalExpenses + financials.fuelCost + financials.wearCost, // Total Real Costs
            netProfit: financials.netProfit,
            miles: totalMiles,
            dateRange: `${startDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} - ${today.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`
        }

        const { data, error } = await resend.emails.send({
            from: 'GigTracker <onboarding@resend.dev>',
            to: [targetEmail],
            subject: `Weekly Report: $${financials.netProfit.toFixed(0)} Profit ­şÜÇ`,
            react: WeeklySummaryEmail(realStats),
        })

        if (error) {
            console.error('Resend Error:', error)
            return { success: false, error: error.message }
        }

        return { success: true, data }

    } catch (error) {
        console.error('Server Action Error:', error)
        return { success: false, error: 'Failed to send email.' }
    }
}

'use server'

import { createClient } from '@/utils/supabase/server'

export async function getExpenseStats(dateRange: { start: string; end: string }) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) return null

    try {
        // Get all daily entries in date range
        const { data: entries, error } = await supabase
            .from('daily_entries')
            .select('date, expenses')
            .eq('user_id', user.id)
            .gte('date', dateRange.start)
            .lte('date', dateRange.end)
            .order('date', { ascending: false })

        if (error) {
            console.error('Error fetching expenses:', error)
            return {
                expenses: [],
                byCategory: {},
                total: 0
            }
        }

        // Flatten all expenses from all entries
        const allExpenses: any[] = []
        entries?.forEach(entry => {
            if (entry.expenses && Array.isArray(entry.expenses)) {
                entry.expenses.forEach((expense: any) => {
                    allExpenses.push({
                        ...expense,
                        date: entry.date
                    })
                })
            }
        })

        // Aggregate by category
        const byCategory: Record<string, { total: number; count: number; items: any[] }> = {}

        allExpenses.forEach(expense => {
            const category = expense.category || 'Other'
            if (!byCategory[category]) {
                byCategory[category] = { total: 0, count: 0, items: [] }
            }
            const amount = parseFloat(expense.amount || 0)
            byCategory[category].total += amount
            byCategory[category].count += 1
            byCategory[category].items.push(expense)
        })

        const total = allExpenses.reduce((acc, e) => acc + parseFloat(e.amount || 0), 0)

        return {
            expenses: allExpenses,
            byCategory,
            total
        }
    } catch (error) {
        console.error('Error in getExpenseStats:', error)
        return {
            expenses: [],
            byCategory: {},
            total: 0
        }
    }
}

import { createClient } from '@/utils/supabase/server'
import { startOfWeek, endOfWeek, subDays, format, startOfDay, endOfDay } from 'date-fns'

interface PlatformEarning {
    platform_name: string
    amount: number
    tips: number
    miles: number
    hours: number
}

interface Expense {
    amount: number
    category: string
    description: string | null
}

interface DatabaseEntry {
    date: string
    platform_earnings: PlatformEarning[]
    expenses: Expense[]
}

interface PlatformStats {
    gross: number
    tips: number
    hours: number
    miles: number
}

interface ExpenseItemDetail {
    amount: number
    description: string
    date: string
}

interface ExpenseCategory {
    category: string
    total: number
    items: ExpenseItemDetail[]
}

const knownPlatforms = [
    'uber',
    'uber eats',
    'lyft',
    'doordash',
    'grubhub',
    'instacart',
    'spark',
    'amazon flex'
]

function getPlatformColor(name: string): string {
    const normalized = name.toLowerCase()
    if (knownPlatforms.includes(normalized)) {
        return `var(--color-${normalized.replace(/\s+/g, '-')})`
    }
    return 'var(--color-other)'
}

export async function getReportsData(startDate?: string, endDate?: string) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) return null

    const end = endDate ? endOfDay(new Date(endDate)) : endOfDay(new Date())
    const start = startDate ? startOfDay(new Date(startDate)) : startOfDay(subDays(end, 6))

    // Fetch entries for the date range
    const { data: entries, error } = await supabase
        .from('daily_entries')
        .select(`
            date,
            platform_earnings ( platform_name, amount, tips, miles, hours ),
            expenses ( amount, category, description )
        `)
        .eq('user_id', user.id)
        .gte('date', format(start, 'yyyy-MM-dd'))
        .lte('date', format(end, 'yyyy-MM-dd'))
        .order('date', { ascending: true })

    if (error || !entries) {
        console.error('Error fetching reports data:', error)
        return { dailyData: [], platformData: [], expenseBreakdown: [] }
    }

    // Fetch user's primary vehicle for depreciation rate
    const { data: vehicle } = await supabase
        .from('vehicles')
        .select('depreciation_rate')
        .eq('user_id', user.id)
        .eq('is_primary', true)
        .single()

    const depreciationRate = vehicle?.depreciation_rate || 0.15

    // 1. Initialize Daily Data Map
    const dailyDataMap = new Map<string, {
        date: string;
        earnings: number;
        expenses: number;
        netProfit: number;
        miles: number;
        depreciationCost: number;
    }>()

    let loopDate = new Date(start)
    while (loopDate <= end) {
        const dateStr = format(loopDate, 'yyyy-MM-dd')
        dailyDataMap.set(dateStr, {
            date: format(loopDate, 'MMM dd'),
            earnings: 0,
            expenses: 0,
            netProfit: 0,
            miles: 0,
            depreciationCost: 0
        })
        loopDate.setDate(loopDate.getDate() + 1)
    }

    // 2. Initialize Platform and Expense Maps
    const platformMap = new Map<string, PlatformStats>()
    const expenseMap = new Map<string, ExpenseCategory>()

    // Type assertion with validation
    const typedEntries = entries as unknown as DatabaseEntry[]

    typedEntries.forEach((entry) => {
        const dayStat = dailyDataMap.get(entry.date)
        if (dayStat) {
            let dailyEarnings = 0
            let dailyMiles = 0
            let dailyHours = 0

            // Earnings & Platform Stats
            entry.platform_earnings.forEach((p) => {
                const total = (p.amount || 0) + (p.tips || 0)
                dailyEarnings += total
                dailyMiles += (p.miles || 0)
                dailyHours += (p.hours || 0)

                const existing = platformMap.get(p.platform_name) || {
                    gross: 0,
                    tips: 0,
                    hours: 0,
                    miles: 0
                }

                platformMap.set(p.platform_name, {
                    gross: existing.gross + total,
                    tips: existing.tips + (p.tips || 0),
                    hours: existing.hours + (p.hours || 0),
                    miles: existing.miles + (p.miles || 0)
                })
            })

            dayStat.earnings += dailyEarnings
            dayStat.miles += dailyMiles

            // Manual Expenses
            let dailyExpenses = 0
            if (entry.expenses && Array.isArray(entry.expenses)) {
                entry.expenses.forEach((e) => {
                    const amount = (e.amount || 0)
                    dailyExpenses += amount

                    // Update Expense Breakdown Map
                    const cat = e.category || 'Other'
                    const existing = expenseMap.get(cat) || {
                        category: cat,
                        total: 0,
                        items: []
                    }

                    existing.total += amount
                    existing.items.push({
                        amount,
                        description: e.description || 'No description',
                        date: entry.date
                    })
                    expenseMap.set(cat, existing)
                })
            }
            dayStat.expenses += dailyExpenses

            // Calculated Depreciation
            const depreciation = dailyMiles * depreciationRate
            dayStat.depreciationCost = depreciation

            if (depreciation > 0) {
                const depCat = 'Vehicle Wear'
                const existingDep = expenseMap.get(depCat) || {
                    category: depCat,
                    total: 0,
                    items: []
                }

                existingDep.total += depreciation
                existingDep.items.push({
                    amount: depreciation,
                    description: `Depreciation for ${dailyMiles.toFixed(1)} miles`,
                    date: entry.date
                })
                expenseMap.set(depCat, existingDep)
            }

            // Net Profit
            dayStat.netProfit = dailyEarnings - dailyExpenses - depreciation
        }
    })

    // 3. Convert Maps to Arrays and Add efficiency metrics
    const dailyData = Array.from(dailyDataMap.values())

    const platformData = Array.from(platformMap.entries()).map(([name, stats]) => {
        const hourlyRate = stats.hours > 0 ? stats.gross / stats.hours : 0
        const tipPct = stats.gross > 0 ? (stats.tips / stats.gross) * 100 : 0
        const earningsPerMile = stats.miles > 0 ? stats.gross / stats.miles : 0

        return {
            name,
            value: stats.gross, // For PieChart
            gross: stats.gross,
            tips: stats.tips,
            hours: stats.hours,
            miles: stats.miles,
            hourlyRate,
            tipPct,
            earningsPerMile,
            fill: getPlatformColor(name)
        }
    }).sort((a, b) => b.gross - a.gross)

    const expenseBreakdown = Array.from(expenseMap.values()).sort((a, b) => b.total - a.total)

    return {
        dailyData,
        platformData,
        expenseBreakdown
    }
}

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { redirect } from 'next/navigation'

export default async function SearchPage({
    searchParams,
}: {
    searchParams: Promise<{ [key: string]: string | string[] | undefined }>
}) {
    const params = await searchParams
    const query = typeof params.q === 'string' ? params.q : ''

    if (!query) {
        redirect('/dashboard')
    }

    return (
        <div className="space-y-6">
            <h1 className="text-3xl font-bold tracking-tight">Search Results</h1>
            <p className="text-muted-foreground">
                Showing results for <span className="font-semibold text-foreground">"{query}"</span>
            </p>

            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {/* Fallback Empty State for now */}
                <Card className="col-span-full border-dashed shadow-none bg-slate-50 dark:bg-slate-900/50">
                    <CardHeader>
                        <CardTitle className="text-lg">No exact matches found</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <p className="text-sm text-muted-foreground">
                            We couldn't find any direct matches for "{query}" in your transactions or vehicles.
                            <br />
                            Try searching for date ranges, platform names, or amounts.
                        </p>
                    </CardContent>
                </Card>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Car, Save, Loader2, Plus, Edit2, Trash2, CheckCircle2 } from 'lucide-react'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { DepreciationCalculator } from '@/components/settings/DepreciationCalculator'
import { saveVehicleAction, deleteVehicleAction } from '@/app/dashboard/settings/vehicle/actions'
import { getEstimatedMPG, getVehicleModels } from '@/utils/api/external'
import { getDepreciationRate } from '@/utils/calculations'
import { CAR_MAKES, CAR_YEARS } from '@/utils/constants'
import { EV_MODELS, ELECTRIC_BRANDS } from '@/utils/vehicle-data'
import { toast } from 'sonner'
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from "@/components/ui/sheet"

interface Vehicle {
    id: string;
    make: string;
    model: string;
    year: number;
    mpg: number;
    depreciation_rate: number;
    is_primary: boolean;
    ownership_type?: string;
    monthly_payment?: number;
    monthly_insurance?: number;
    payment_cycle?: string;
    fuel_type?: string;
    electricity_cost_per_kwh?: number;
}

interface VehicleSettingsFormProps {
    initialVehicles: Vehicle[]
}

export function VehicleSettingsForm({ initialVehicles }: VehicleSettingsFormProps) {
    const [vehicles, setVehicles] = useState<Vehicle[]>(initialVehicles)
    const [isSheetOpen, setIsSheetOpen] = useState(false)
    const [editingVehicle, setEditingVehicle] = useState<Vehicle | null>(null)
    const [isLoading, setIsLoading] = useState(false)

    // Form State
    const [year, setYear] = useState('')
    const [make, setMake] = useState('')
    const [model, setModel] = useState('')
    const [models, setModels] = useState<string[]>([])
    const [mpg, setMpg] = useState('')
    const [depreciationRate, setDepreciationRate] = useState(0.20)
    const [ownershipType, setOwnershipType] = useState('owned')
    const [monthlyPayment, setMonthlyPayment] = useState('')
    const [monthlyInsurance, setMonthlyInsurance] = useState('')
    const [paymentCycle, setPaymentCycle] = useState('monthly')
    const [fuelType, setFuelType] = useState('gasoline')
    const [electricityCost, setElectricityCost] = useState('0.15')

    const [fetchingModels, setFetchingModels] = useState(false)
    const [fetchingMPG, setFetchingMPG] = useState(false)

    // Reset form when opening sheet for Add or Edit
    useEffect(() => {
        if (isSheetOpen) {
            if (editingVehicle) {
                setYear(editingVehicle.year.toString())
                setMake(editingVehicle.make)
                setModel(editingVehicle.model)
                setMpg(editingVehicle.mpg.toString())
                setDepreciationRate(editingVehicle.depreciation_rate)
                setOwnershipType(editingVehicle.ownership_type || 'owned')
                setMonthlyPayment(editingVehicle.monthly_payment?.toString() || '')
                setMonthlyInsurance(editingVehicle.monthly_insurance?.toString() || '')
                setPaymentCycle(editingVehicle.payment_cycle || 'monthly')
                setFuelType(editingVehicle.fuel_type || 'gasoline')
                setElectricityCost(editingVehicle.electricity_cost_per_kwh?.toString() || '0.15')
            } else {
                setYear('')
                setMake('')
                setModel('')
                setMpg('')
                setDepreciationRate(0.20)
                setOwnershipType('owned')
                setMonthlyPayment('')
                setMonthlyInsurance('')
                setPaymentCycle('monthly')
                setFuelType('gasoline')
                setElectricityCost('0.15')
            }
        }
    }, [isSheetOpen, editingVehicle])

    // Load available models when year/make change
    useEffect(() => {
        async function loadModels() {
            if (!year || !make) return
            setFetchingModels(true)
            try {
                const modelsList = await getVehicleModels(year, make)
                setModels(modelsList)
            } catch (error) {
                console.error("Failed to load models:", error)
            } finally {
                setFetchingModels(false)
            }
        }
        loadModels()
    }, [year, make])

    // Update MPG and Depreciation when model changes
    useEffect(() => {
        async function syncVehicleData() {
            if (!year || !make || !model) return

            const newRate = getDepreciationRate(make, model, parseInt(year))
            setDepreciationRate(newRate)

            setFetchingMPG(true)
            try {
                const result = await getEstimatedMPG(year, make, model)
                if (result) {
                    setMpg(result.value.toString())
                    setFuelType(result.fuelType)
                    if (result.fuelType === 'electric') {
                        toast.success(`Electric vehicle detected! Efficiency: ${result.value} mi/kWh`)
                    }
                }
            } catch (error) {
                console.error("Failed to fetch MPG:", error)
            } finally {
                setFetchingMPG(false)
            }
        }

        const isInitialLoad = editingVehicle &&
            year === editingVehicle.year.toString() &&
            make === editingVehicle.make &&
            model === editingVehicle.model

        if (!isInitialLoad && isSheetOpen) {
            syncVehicleData()
        }
    }, [model, year, make])

    async function handleSave(e: React.FormEvent) {
        e.preventDefault()
        setIsLoading(true)
        const formData = new FormData()
        formData.set('year', year)
        formData.set('make', make)
        formData.set('model', model)

        // Handle locale-specific decimals (comma to dot)
        const safeMpg = mpg.toString().replace(',', '.')
        const safeDepreciation = depreciationRate.toString().replace(',', '.')
        const safePayment = monthlyPayment.toString().replace(',', '.')
        const safeInsurance = monthlyInsurance.toString().replace(',', '.')

        formData.set('mpg', safeMpg)
        formData.set('depreciation_rate', safeDepreciation)
        formData.set('ownership_type', ownershipType)
        formData.set('monthly_payment', safePayment)
        formData.set('monthly_insurance', safeInsurance)
        formData.set('payment_cycle', paymentCycle)

        // Auto-detect electric vehicles
        const evBrands = ['Tesla', 'Rivian', 'Lucid', 'Polestar']
        const detectedFuelType = evBrands.includes(make) ? 'electric' : fuelType
        formData.set('fuel_type', detectedFuelType)
        formData.set('electricity_cost_per_kwh', electricityCost.replace(',', '.'))

        try {
            const result = await saveVehicleAction(formData, editingVehicle?.id)
            if (result.success) {
                toast.success(editingVehicle ? 'Vehicle updated!' : 'Vehicle added!')
                setIsSheetOpen(false)
                // Window reload is a simple way to refresh server data, 
                // but revalidatePath should handle it if this was a purely server component setup.
                // However, since we are in a client component, we rely on the server action revalidating tags/paths.
            }
        } catch (error) {
            toast.error('Failed to save vehicle')
        } finally {
            setIsLoading(false)
        }
    }

    async function handleDelete(id: string) {
        if (!confirm('Are you sure you want to delete this vehicle?')) return
        try {
            const result = await deleteVehicleAction(id)
            if (result.success) {
                toast.success('Vehicle removed')
            } else {
                toast.error(result.error || 'Failed to delete')
            }
        } catch (error) {
            toast.error('Error deleting vehicle')
        }
    }

    const years = Array.from({ length: 30 }, (_, i) => (new Date().getFullYear() - i).toString())

    return (
        <div className="space-y-6">
            <div className="grid gap-4">
                {vehicles.map((v) => (
                    <div
                        key={v.id}
                        className={`glass-card p-5 border-white/5 flex items-center justify-between group transition-all hover:scale-[1.01] ${v.is_primary ? 'ring-2 ring-emerald-500/20' : ''}`}
                    >
                        <div className="flex items-center gap-4">
                            <div className={`p-3 rounded-xl ${v.is_primary ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'bg-white/5 text-slate-400'}`}>
                                <Car className="size-6" />
                            </div>
                            <div>
                                <div className="flex items-center gap-2">
                                    <h3 className="font-bold text-slate-900 dark:text-white">{v.year} {v.make} {v.model}</h3>
                                    {v.is_primary && (
                                        <span className="flex items-center gap-1 text-[10px] font-bold uppercase tracking-wider text-emerald-500 bg-emerald-500/10 px-2 py-0.5 rounded-full">
                                            <CheckCircle2 className="size-3" /> Active
                                        </span>
                                    )}
                                </div>
                                <div className="flex items-center gap-3 mt-1 flex-wrap">
                                    <span className="text-xs text-slate-500 font-medium">{v.mpg} MPG</span>
                                    <span className="text-xs text-slate-400">ÔÇó</span>
                                    <span className="text-xs text-slate-500 font-medium capitalize">{v.ownership_type || 'Owned'}</span>
                                    <span className="text-xs text-slate-400">ÔÇó</span>
                                    {v.ownership_type === 'owned' || !v.ownership_type ? (
                                        <span className="text-xs text-slate-500 font-medium">${v.depreciation_rate}/mile wear</span>
                                    ) : (
                                        <span className="text-xs text-emerald-500 font-bold italic">No depreciation</span>
                                    )}
                                    {(Number(v.monthly_payment) > 0 || Number(v.monthly_insurance) > 0) && (
                                        <>
                                            <span className="text-xs text-slate-400">ÔÇó</span>
                                            <span className="text-xs text-slate-500 font-medium">${(Number(v.monthly_payment || 0) + Number(v.monthly_insurance || 0)).toLocaleString()}/mo fixed</span>
                                        </>
                                    )}
                                </div>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <Button
                                variant="ghost"
                                size="icon"
                                className="size-9 rounded-xl hover:bg-white/10"
                                onClick={() => {
                                    setEditingVehicle(v)
                                    setIsSheetOpen(true)
                                }}
                            >
                                <Edit2 className="size-4 text-emerald-500" />
                            </Button>
                            <Button
                                variant="ghost"
                                size="icon"
                                className="size-9 rounded-xl hover:bg-ruby-500/10"
                                onClick={() => handleDelete(v.id)}
                            >
                                <Trash2 className="size-4 text-ruby-500" />
                            </Button>
                        </div>
                    </div>
                ))}

                <Button
                    variant="outline"
                    className="h-20 border-dashed border-2 border-white/10 hover:border-emerald-500/50 hover:bg-emerald-500/5 rounded-2xl flex items-center justify-center gap-3 transition-all group"
                    onClick={() => {
                        setEditingVehicle(null)
                        setIsSheetOpen(true)
                    }}
                >
                    <div className="p-2 rounded-lg bg-emerald-500/10 text-emerald-500 group-hover:scale-110 transition-transform">
                        <Plus className="size-5" />
                    </div>
                    <span className="font-bold text-slate-900 dark:text-slate-100 italic">Add Another Vehicle</span>
                </Button>
            </div>

            <Sheet open={isSheetOpen} onOpenChange={setIsSheetOpen}>
